#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n; if(!(cin>>n)) return 0;
    vector<long long> nums(n);
    for(int i=0;i<n;++i)cin>>nums[i];
    long long target;cin>>target;
    sort(nums.begin(), nums.end());
    vector<array<long long,4>> res;
    for(int i=0;i<n-3;++i){
        if(i>0 && nums[i]==nums[i-1]) continue;
        if(nums[i]+nums[i+1]+nums[i+2]+nums[i+3] > target) break;
        if(nums[i]+nums[n-3]+nums[n-2]+nums[n-1] < target) continue;
        for(int j=i+1;j<n-2;++j){
            if(j>i+1 && nums[j]==nums[j-1]) continue;
            if(nums[i]+nums[j]+nums[j+1]+nums[j+2] > target) break;
            if(nums[i]+nums[j]+nums[n-2]+nums[n-1] < target) continue;
            int l=j+1, r=n-1;
            while(l<r){
                long long sum=nums[i]+nums[j]+nums[l]+nums[r];
                if(sum==target){
                    res.push_back({nums[i],nums[j],nums[l],nums[r]});
                    long long lv=nums[l], rv=nums[r];
                    while(l<r && nums[l]==lv) ++l;
                    while(l<r && nums[r]==rv) --r;
                }else if(sum<target) ++l; else --r;
            }
        }
    }
    // output as Python-like list of lists
    cout<<"[";
    for(size_t i=0;i<res.size();++i){
        if(i) cout<<", ";
        cout<<"["<<res[i][0]<<", "<<res[i][1]<<", "<<res[i][2]<<", "<<res[i][3]<<"]";
    }
    cout<<"]";
    return 0;
}
